from fractions import Fraction

x, y, n = map(int, input().split())


def gcd(a, b):
    if b == 0:
        return a
    return gcd(b, a % b)


def lcm(a, b):
    return a * b // gcd(a, b)


def get_ans(x, y, n):
    ans = Fraction(0, 1)
    for i in range(1, n + 1):
        if i % y == 0:
            continue
        t = Fraction(x * i, y)
        if abs(ans - t) > abs(t - Fraction(x, y)):
            ans = t
    return ans


ans = get_ans(x, y, n)
print(ans.numerator, '/', ans.denominator, sep='')
